import{j as e,b as a,c as r,a2 as o}from"./chunks/framework.BDRKwY9B.js";const c=JSON.parse('{"title":"统一联合记忆","description":"统一联合记忆（Unified Associative Memory）的设计深度——图式事实记忆、情景记忆与知识图谱经验记忆。","frontmatter":{"title":"统一联合记忆","description":"统一联合记忆（Unified Associative Memory）的设计深度——图式事实记忆、情景记忆与知识图谱经验记忆。","order":5},"headers":[],"relativePath":"architecture/memory-system.md","filePath":"architecture/memory-system.md","lastUpdated":1778837174000}'),i={name:"architecture/memory-system.md"};function l(d,t,u,n,m,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="统一联合记忆" tabindex="-1">统一联合记忆 <a class="header-anchor" href="#统一联合记忆" aria-label="Permalink to &quot;统一联合记忆&quot;">​</a></h1><p>AuroraBot 的记忆不是&quot;把对话存下来&quot;，而是<strong>结构化地生长</strong>。统一联合记忆（Unified Associative Memory）借助 mem0 实现图式的事实记忆、情景记忆与知识图谱经验记忆，覆盖所有认知活动。</p><p><strong>挼挼如是说</strong></p><blockquote><p>大多数 chatbot 的记忆是一条线——上一句接下一句，最多往前翻几轮。AuroraBot 的记忆是一张网——你说过的事、她做过的事、她对自己的评价、甚至她&quot;感觉&quot;到的趋势，都会被织进同一张图里。下次她做决策的时候，不是翻&quot;历史记录&quot;，而是在图里找&quot;跟现在最相关的那几个节点&quot;。</p></blockquote><h2 id="为什么不是线性记忆" tabindex="-1">为什么不是线性记忆 <a class="header-anchor" href="#为什么不是线性记忆" aria-label="Permalink to &quot;为什么不是线性记忆&quot;">​</a></h2><p>线性记忆的问题：</p><ul><li>只能按时间顺序检索，无法按语义关联跳转</li><li>对话记忆丢掉了&quot;为什么做这个决策&quot;的上下文</li><li>不同来源的记忆（对话、行动、自我评估）无法融合</li></ul><p>统一联合记忆的设计意图：</p><ul><li>所有认知活动——对话、计划、动作、自我评估——都写入同一张图</li><li>记忆之间通过关系边连接，形成可遍历的关联网络</li><li>检索时可以沿边跳跃，找到&quot;跟当前最相关&quot;的记忆片段</li></ul><h2 id="三类记忆" tabindex="-1">三类记忆 <a class="header-anchor" href="#三类记忆" aria-label="Permalink to &quot;三类记忆&quot;">​</a></h2><h3 id="图式事实记忆-graph-based-fact-memory" tabindex="-1">图式事实记忆（Graph-based Fact Memory） <a class="header-anchor" href="#图式事实记忆-graph-based-fact-memory" aria-label="Permalink to &quot;图式事实记忆（Graph-based Fact Memory）&quot;">​</a></h3><p>将离散的事实编码为图中的节点和边：</p><ul><li><strong>节点</strong> — 实体（人、事件、概念）</li><li><strong>边</strong> — 关系（&quot;说过&quot;、&quot;属于&quot;、&quot;导致&quot;）</li><li><strong>更新</strong> — 新事实不覆盖旧事实，而是在图中新增节点和边</li></ul><h3 id="情景记忆-episodic-memory" tabindex="-1">情景记忆（Episodic Memory） <a class="header-anchor" href="#情景记忆-episodic-memory" aria-label="Permalink to &quot;情景记忆（Episodic Memory）&quot;">​</a></h3><p>记录&quot;发生了什么&quot;的时序片段：</p><ul><li>每次对话、每个行动、每次自我评估都是一个情景片段</li><li>情景之间通过时间边和因果边连接</li><li>检索时可以&quot;回想&quot;相关情景的完整上下文</li></ul><h3 id="知识图谱经验记忆-knowledge-graph-experience-memory" tabindex="-1">知识图谱经验记忆（Knowledge Graph Experience Memory） <a class="header-anchor" href="#知识图谱经验记忆-knowledge-graph-experience-memory" aria-label="Permalink to &quot;知识图谱经验记忆（Knowledge Graph Experience Memory）&quot;">​</a></h3><p>从事实和情景中抽象出的&quot;经验&quot;：</p><ul><li>不是&quot;某年某月发生了什么&quot;，而是&quot;类似情况下她倾向于怎么做&quot;</li><li>经验会随着时间演化——CriticAgent 的自我评估会更新经验权重</li><li>这是她&quot;性格会偏移、口吻会老化&quot;的底层机制</li></ul><h2 id="与-mem0-的关系" tabindex="-1">与 mem0 的关系 <a class="header-anchor" href="#与-mem0-的关系" aria-label="Permalink to &quot;与 mem0 的关系&quot;">​</a></h2><p>统一联合记忆借助 <a href="https://github.com/mem0ai/mem0" target="_blank" rel="noreferrer">mem0</a> 作为基础设施：</p><ul><li>mem0 提供图存储、向量检索和记忆更新管道</li><li>AuroraBot 在 mem0 之上封装了认知活动的写入/检索接口</li><li>所有记忆操作通过 Brain 层统一网关进行，不直接暴露给 App 或 Kernel</li></ul><h2 id="覆盖范围" tabindex="-1">覆盖范围 <a class="header-anchor" href="#覆盖范围" aria-label="Permalink to &quot;覆盖范围&quot;">​</a></h2><p>统一联合记忆不仅覆盖&quot;对话&quot;，而是覆盖所有认知活动：</p><table tabindex="0"><thead><tr><th>来源</th><th>写入内容</th></tr></thead><tbody><tr><td>对话（QQ）</td><td>对话情景、用户印象</td></tr><tr><td>计划（PlanAgent）</td><td>计划记录、决策理由</td></tr><tr><td>动作（ExecuteAgent）</td><td>执行结果、成功/失败</td></tr><tr><td>自我评估（CriticAgent）</td><td>自我评价、倾向调整</td></tr><tr><td>日记（Diary App）</td><td>日记条目</td></tr><tr><td>闹钟（Alarm App）</td><td>提醒事件</td></tr></tbody></table><h2 id="当前状态" tabindex="-1">当前状态 <a class="header-anchor" href="#当前状态" aria-label="Permalink to &quot;当前状态&quot;">​</a></h2><ul><li>记忆系统的设计已完成，mem0 整合在推进中</li><li>当前阶段使用 JSON 文件作为过渡方案（<code>data/kernel/</code> 下的队列文件）</li><li>统一联合记忆是&quot;认知节点插件体系开放&quot;的前置依赖之一</li></ul><h2 id="下一步阅读" tabindex="-1">下一步阅读 <a class="header-anchor" href="#下一步阅读" aria-label="Permalink to &quot;下一步阅读&quot;">​</a></h2><ul><li>想理解认知架构全貌：读 <a href="./brain-architecture.html">认知架构</a></li><li>想理解节点如何存取记忆：读 <a href="./node-system.html">节点系统</a></li><li>想理解内核如何调度记忆节点：读 <a href="./kernel-runtime.html">内核运行时</a></li></ul>',29)])])}const p=e(i,[["render",l]]);export{c as __pageData,p as default};
